// shadcn
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";

// constants
const testimonials = [
  {
    name: "Joseph William",
    avatar: "https://cdn.uiable.com/block/team2.png",
    initials: "JW",
    text: "At half-past eight the door opened, the policeman appeared, and requesting them to follow him.",
  },
  {
    name: "Shirley Hoe",
    avatar: "https://cdn.uiable.com/block/team1.png",
    initials: "SH",
    text: "At half-past eight the door opened, the policeman appeared, and requesting them to follow him.",
  },
  {
    name: "Shirley Hoe",
    avatar: "https://cdn.uiable.com/block/team3.png",
    initials: "SH",
    text: "At half-past eight the door opened, the policeman appeared, and requesting them to follow him.",
  },
  {
    name: "Joseph William",
    avatar: "https://cdn.uiable.com/block/team4.png",
    initials: "JW",
    text: "At half-past eight the door opened, the policeman appeared, and requesting them to follow him.",
  },
];

//  ------------------------------ | TESTIMONIAL 1 | ------------------------------  //

//  ------------------------------ | TESTIMONIAL1 | ------------------------------  //

export default function Testimonial1() {
  return (
    <section className="py-20">
      <div className="container mx-auto px-6">
        <div className="grid grid-cols-12 mb-10">
          <div className="col-span-12 text-start">
            <h2>What Clients Say</h2>
            <p className="text-muted-foreground mt-3 max-w-4xl">
              At half-past eight the door opened, the policeman appeared and
              requesting them to follow him, led way to an adjoining hall.
            </p>
          </div>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 md:gap-12">
          {testimonials.map((t, i) => (
            <div key={i} className="flex items-start gap-4 py-4">
              <Avatar className="h-18 w-18">
                <AvatarImage src={t.avatar} alt={t.name} />
                <AvatarFallback>{t.initials}</AvatarFallback>
              </Avatar>
              <div>
                <h5 className="text-foreground mb-4">{t.name}</h5>
                <p className="text-muted-foreground">{t.text}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
